#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
int T,n;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void upd(int l,int r){
    cout<<"1 "<<l<<" "<<r<<"\n";
    fflush(stdout);return;
}
int ask(int l,int r){
    cout<<"2 "<<l<<" "<<r<<"\n";
    fflush(stdout);
    int x;cin>>x;return x;
}
void know(int x,int y){
    cout<<"3 "<<x<<" "<<y<<"\n";
    fflush(stdout);return;
}
int main(){
    cin>>T;
    while(T--){
        cin>>n;
        upd(1,n);//翻转
        int cnt0=ask(1,n);
        //查询总共点亮的灯泡数
        if(cnt0==n-2){
            int l=1,r=n;
            int ansL=0,ansR=0;
            while(l<r){
                int mid=(l+r)>>1;
                int res=ask(1,mid);
                if(res==mid-2)r=mid;
                else l=mid+1;
            }//找到区间右端点
            ansR=l,l=1,r=n;
            while(l<r){
                int mid=(l+r+1)>>1;
                int res=ask(mid,n);
                if(res==n-mid-1)l=mid;
                else r=mid-1;
            }//找到区间左端点
            ansL=l;
            know(ansL,ansR);//报告答案
        }else if(cnt0==n){
            upd(1,n);//再翻转一次
            //此时所有灯泡都是暗的，除了两个坏的是亮的
            int l=1,r=n;
            int ansL=0,ansR=0;
            while(l<r){
                int mid=(l+r)>>1;
                int res=ask(1,mid);
                if(res==2)r=mid;
                else l=mid+1;
            }//找到区间右端点
            ansR=l,l=1,r=n;
            while(l<r){
                int mid=(l+r+1)>>1;
                int res=ask(mid,n);
                if(res==2)l=mid;
                else r=mid-1;
            }//找到区间左端点
            ansL=l;
            know(ansL,ansR);//报告答案
        }else if(cnt0==n-1){
            int l=1,r=n,ansL=0,ansR=0;
            while(l<r){
                int mid=(l+r)>>1;
                int len=mid-l+1;
                int res=ask(l,mid);
                if(res!=len)r=mid;
                else l=mid+1;
            }//找到暗的那一个
            ansL=l;l=1,r=n;
            upd(1,n);//再次翻转
            while(l<r){
                int mid=(l+r)>>1;
                if(ansL==mid){//与损坏灯泡重合
                    if(l==mid){l++;continue;}//增大
                    int res=ask(l,mid-1);
                    if(res)r=mid-1;
                    else l=mid+1;
                }else if(l<=ansL&&ansL<mid){//介于之间
                    int res=ask(mid,r);
                    if(res)l=mid;
                    else r=mid-1;
                }else{
                    int res=ask(l,mid);
                    if(res)r=mid;
                    else l=mid+1;
                }
            }
            ansR=l;
            know(ansL,ansR);//报告答案
        }else //不存在
            cout<<"wrong answer.\n";
    }
    return 0;
}
